module RefModule (
	input clk,
	input reset,
	input clk_enable,
	input [31:0] data_in,
	output reg [31:0] data_out);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		data_out <= 32'b0;
	else if (clk_enable)
		data_out <= data_in;
end

endmodule
